import{_ as l,c as a,j as e,a as t,o}from"./chunks/framework.B0cMFUTE.js";const d=JSON.parse('{"title":"对人工智能发展的见解","description":"","frontmatter":{"title":"对人工智能发展的见解","tags":null,"categories":["monologue\\r"],"date":"2024-12-07T14:56:47.000Z","abbrlink":24120714,"updated":"2024-10-29 22:49"},"headers":[],"relativePath":"monologue/对人工智能发展的见解.md","filePath":"monologue/对人工智能发展的见解.md"}'),r={name:"monologue/对人工智能发展的见解.md"};function u(s,n,p,_,i,m){return o(),a("div",null,n[0]||(n[0]=[e("p",null,"12-6 人脑中可能有量子的作用，从而可以进行高效的大规模计算。对此，我简单了解了现有的量子神经网络（Quantum Neural Networks，QNN），发现QNN仅仅是将神经网络的固有架构移植到量子计算机上，利用量子计算机的量子计算来提高运算效率，但是在如今量子硬件还未有很大突破的情况下，量子计算机本身就极为稀有与昂贵，且能力有限。量子计算是利用光子的纠缠态进行掐头去尾的运算，现在的研究依赖于物理上的构造，如何构造多少比特的纠缠态，从而实现一次性计算多少量级的运算，以及现有的量子计算机只能计算特定的任务。现在的量子计算机很难应用到神经网络上。对硬件上无法硬要求，因此我应该把目光放到算法与架构层面。",-1),e("p",null,"相关方向：量子神经网络（QNN）",-1),e("p",null,[t("12-7 杨立昆（Yann LeCun）是Facebook首席人工智能科学家和纽约大学教授，2018年图灵奖（Turing Award）得主，他22年提出了"),e("em",null,[e("strong",null,"世界模型与自监督学习")]),t("，我认为这与我的想法非常相像，但仍有一些不同。理想中的AI是通过不断丰富接触到的常识，来构建自我，而现阶段的AI仅仅是在包罗万象的丰富常识，却没有构建自我，是大而全的数据驱动的网络。我认为应该把常识剥离出去，将网络抽象成复杂网络，由分布式的多个小网络以及一个中心处理网络组成，其中小网络负责学习常识，由中心网络与数据同时驱动，而中心网络则是由固有常识（探索世界，自监督）以及任务驱动。这样将常识数据收集者与任务驱动者分离，在他们之间建立统一的接口，从而实现分布式的并行计算，可迁移性，数据的可复用性。这种架构很适合世界模型的构建，但目前我的想法仅仅是想法阶段，具体实现需要学习更多知识后，一步步解决。")],-1),e("p",null,"例如建立一个蚂蚁模型，它仅仅去构建一个蚂蚁常识的数据网络，它训练到的有蚂蚁外貌、机能等数据，而中心人网络则是需要蚂蚁有关常识时，与蚂蚁模型进行通信，调用蚂蚁网络。相应的，中心人网络只需要使用自监督去选择调用哪些常识即可。再套一层娃，蚂蚁网络当做中心网络，蚂蚁网络的训练通过对花草树木等其他小网络的通信进行自主训练，以此类推，从而构建了世界网络，每个网络都是通过与其他生物/物体进行观测与通信而自发完善自身，而我们仅仅需要其中人这个网络即可。",-1),e("p",null,"了解到的相关方向：世界模型、自监督学习、类脑计算、多任务学习（Multi task learning）",-1),e("p",null,"类脑计算目前感觉仍然是想构建大而全的网络，仅仅是对内部的架构进行了类脑调整，可以借鉴内部结构。",-1),e("p",null,"12-11 无监督学习、Boltzmann machine",-1)]))}const N=l(r,[["render",u]]);export{d as __pageData,N as default};
